package com.raonmate.backend.budget.application; import com.raonmate.backend.budget.api.*; import com.raonmate.backend.budget.domain.*; import com.raonmate.backend.global.error.ResourceNotFoundException; import com.raonmate.backend.workshop.domain.*; import java.math.BigDecimal; import java.util.*; import lombok.RequiredArgsConstructor; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional;
@Service @RequiredArgsConstructor @Transactional(readOnly=true) public class BudgetService{private final BudgetPlanRepository plans;private final WorkshopRepository workshops;public BudgetResponse get(UUID id){return BudgetResponse.from(plans.findByWorkshopId(id).orElseThrow(()->new ResourceNotFoundException("예산 계획이 없습니다.")));}@Transactional public BudgetResponse initialize(UUID id){Workshop w=workshops.findById(id).orElseThrow(()->new ResourceNotFoundException("워크숍을 찾을 수 없습니다."));BudgetPlan p=plans.findByWorkshopId(id).orElseGet(()->new BudgetPlan(w));if(p.getItems().isEmpty()){BigDecimal limit=w.getBudgetPerPerson()==null?BigDecimal.ZERO:w.getBudgetPerPerson().multiply(BigDecimal.valueOf(w.getExpectedParticipants()));p.replace(List.of(new BudgetPlan.Item("VENUE","장소 및 숙박",limit.multiply(new BigDecimal("0.55")),"예상 배정"),new BudgetPlan.Item("MEAL","식사",limit.multiply(new BigDecimal("0.25")),"예상 배정"),new BudgetPlan.Item("ACTIVITY","프로그램",limit.multiply(new BigDecimal("0.20")),"예상 배정")));}return BudgetResponse.from(plans.save(p));}@Transactional public BudgetResponse update(UUID id,BudgetRequest r){BudgetPlan p=plans.findByWorkshopId(id).orElseThrow(()->new ResourceNotFoundException("예산 계획이 없습니다."));p.replace(r.items().stream().map(i->new BudgetPlan.Item(i.category(),i.name(),i.amount(),i.note())).toList());return BudgetResponse.from(p);}}
